from agent import *from models.products import *def run(context, session):    session.sessionbreakers=[SessionBreak(max_requests=10000)]    session.queue(Request('https://www.gamingnexus.com/Article/MoreReviews?startCount=1', use='curl'), process_revlist, dict(index=1))def process_revlist(data, context, session):    revs = data.xpath("//h3/a")    for rev in revs:        title = rev.xpath(".//text()").string()        url = rev.xpath("@href").string()        session.queue(Request(url, use='curl'), process_review, dict(context, title=title, url=url))        if revs:        nextindex = context['index'] + 1        nexturl = 'https://www.gamingnexus.com/Article/MoreReviews?startCount=' + str(nextindex)        session.queue(Request(nexturl, use='curl'), process_revlist, dict(context, index=nextindex))def process_review(data, context, session):    product = Product()    review = Review()    product.ssid = context['url'].split('/')[-2]    product.url = context['url']    meta = data.xpath("//div[@id='divArticle']/div[3]//text()").string(multiple=True)    if meta:        product.name = meta.split('More On:')[1]        date = meta.split('on')[1].split('for')[0]        review.date = date        platform = meta.split('for')[1].split('More On')[0]        product.category = 'Games|' + platform    else:        product.name = context['title'].split(' Review')[0]        product.category = 'Games'        review.title = context['title']    review.ssid = product.ssid    review.type = 'pro'    review.url = context['url']        authors = data.xpath("//div[@id='divArticle']/div[3]/a")    for author in authors:        author_name = author.xpath(".//text()").string()        author_url = author.xpath("@href").string()        review.authors.append(Person(name=author_name, profile_url=author_url, ssid=author_name))        conclusion = data.xpath("//div[@class='row']/div[@id='divArticle']/div[5]/div[1]//text()").string(multiple=True)    if conclusion:        review.properties.append(ReviewProperty(type='conclusion', value=conclusion))        excerpt = data.xpath("//div[@class='row']/div[@id='divArticle']/div[4]/p//text()").string(multiple=True)    if excerpt:        review.properties.append(ReviewProperty(type='excerpt', value=excerpt))        grade_overall = data.xpath("//div[@class='row']/div[@id='divArticle']//h2[contains(.,'Rating:')]//text()").string()    if grade_overall:        grade_overall = grade_overall.split('Rating: ')[1].split(' ')[0]        review.grades.append(Grade(type='overall', value=float(grade_overall), best=10.0))        product.reviews.append(review)    session.emit(product)